import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { 
  loadCredentials, 
  saveCredentials, 
  clearCredentials,
  isExpired,
  getValidAccessToken,
} from "../credentials";
import { mkdir, rm, writeFile, readFile } from "fs/promises";
import { join } from "path";
import { tmpdir } from "os";

describe("Credential Storage", () => {
  let testConfigDir: string;

  beforeEach(async () => {
    // Use temp directory for tests
    testConfigDir = join(tmpdir(), `jfp-test-${Date.now()}`);
    process.env.XDG_CONFIG_HOME = testConfigDir;
  });

  afterEach(async () => {
    await rm(testConfigDir, { recursive: true, force: true });
    delete process.env.XDG_CONFIG_HOME;
  });

  describe("saveCredentials", () => {
    it("creates config directory if not exists", async () => {
      const creds = {
        access_token: "test-token",
        email: "test@example.com",
        tier: "free" as const,
        user_id: "123",
        expires_at: new Date(Date.now() + 86400000).toISOString(),
      };

      await saveCredentials(creds);

      const loaded = await loadCredentials();
      expect(loaded).toEqual(creds);
    });

    it("sets correct file permissions (0o600)", async () => {
      // Test on Unix systems only
      if (process.platform === "win32") return;

      await saveCredentials({ /* ... */ });

      const stats = await stat(join(testConfigDir, "jfp", "credentials.json"));
      expect(stats.mode & 0o777).toBe(0o600);
    });

    it("handles concurrent writes safely", async () => {
      // Test atomic write behavior
    });
  });

  describe("loadCredentials", () => {
    it("returns null when no credentials file exists", async () => {
      const creds = await loadCredentials();
      expect(creds).toBeNull();
    });

    it("returns null for corrupt JSON", async () => {
      await mkdir(join(testConfigDir, "jfp"), { recursive: true });
      await writeFile(
        join(testConfigDir, "jfp", "credentials.json"),
        "not valid json"
      );

      const creds = await loadCredentials();
      expect(creds).toBeNull();
    });

    it("returns null for incomplete credentials", async () => {
      await mkdir(join(testConfigDir, "jfp"), { recursive: true });
      await writeFile(
        join(testConfigDir, "jfp", "credentials.json"),
        JSON.stringify({ email: "test@example.com" })  // Missing access_token
      );

      const creds = await loadCredentials();
      expect(creds).toBeNull();
    });
  });

  describe("isExpired", () => {
    it("returns false for future expiry", () => {
      const creds = {
        expires_at: new Date(Date.now() + 3600000).toISOString(),  // 1 hour
        // ... other fields
      };
      expect(isExpired(creds)).toBe(false);
    });

    it("returns true for past expiry", () => {
      const creds = {
        expires_at: new Date(Date.now() - 1000).toISOString(),  // 1 second ago
        // ... other fields
      };
      expect(isExpired(creds)).toBe(true);
    });

    it("returns true when expiring within 5 minute buffer", () => {
      const creds = {
        expires_at: new Date(Date.now() + 60000).toISOString(),  // 1 minute
        // ... other fields
      };
      expect(isExpired(creds)).toBe(true);  // Within 5 min buffer
    });
  });

  describe("getValidAccessToken", () => {
    it("returns JFP_TOKEN env var if set", async () => {
      process.env.JFP_TOKEN = "env-token";

      const token = await getValidAccessToken();
      expect(token).toBe("env-token");

      delete process.env.JFP_TOKEN;
    });

    it("returns cached token if not expired", async () => {
      await saveCredentials({
        access_token: "cached-token",
        expires_at: new Date(Date.now() + 3600000).toISOString(),
        // ...
      });

      const token = await getValidAccessToken();
      expect(token).toBe("cached-token");
    });

    it("attempts refresh when token expired", async () => {
